1533→      renderLeaderboard(users, 'teamLeaderboardSession', 'sessionPct', 'weeklyPct', 'mo');
1534→      renderLeaderboard(users, 'teamLeaderboardWeekly', 'weeklyPct', 'sessionPct', 'sess');
1535→    }
1536→
1537→    // My Status Card
1538→    renderMyStatus(data);
1539→
1540→    // Utilisation Gauge
1541→    const INR_RATE = 94.7;
1542→    const fmtINR = (v) => '\u20B9' + new Intl.NumberFormat('en-IN', { maximumFractionDigits: 0 }).format(v);
1543→    const totalExtraSpent = data.users.reduce((s, u) => s + (u.extraUsageSpent || 0), 0);
1544→    const budgetUSD = data.users.reduce((s, u) => s + (u.budget || 0), 0);
1545→    // Utilised = each user's monthly multiplier × their plan cost + extra usage
1546→    const utilisedUSD = data.users.reduce((s, u) => {
1547→      const userMult = (u.weeklyPct || 0) / 100;
1548→      const userPlanCost = (u.budget || 200) / (u.numPlans || 1); // per-plan cost
1549→      return s + (userMult * userPlanCost) + (u.extraUsageSpent || 0);
1550→    }, 0);
1551→    const pct = budgetUSD > 0 ? Math.round((utilisedUSD / budgetUSD) * 100) : 0;
1552→    const sessionsActive = data.users.filter(u => (u.sessionPct || 0) > 0).length;
1553→
1554→    document.getElementById('gaugeUtilised').textContent = fmtINR(utilisedUSD * INR_RATE);
1555→    document.getElementById('gaugeBudget').textContent = fmtINR(budgetUSD * INR_RATE);
1556→    document.getElementById('gaugeUSD').textContent = '[$' + Math.round(utilisedUSD).toLocaleString('en-US') + ' / $' + budgetUSD.toLocaleString('en-US') + ']';
1557→
1558→    const bar = document.getElementById('gaugeBarFill');
1559→    const barWidth = Math.min(pct, 150); // allow visual overflow past 100%
1560→    bar.style.width = barWidth + '%';
1561→    // Color: red < 25%, orange 25-50%, yellow 50-75%, green > 75%, purple > 100%
1562→    if (pct > 100) bar.style.background = 'linear-gradient(90deg, #2DC653, #a855f7)';
1563→    else if (pct >= 75) bar.style.background = 'linear-gradient(90deg, #2DC653, #22c55e)';
1564→    else if (pct >= 50) bar.style.background = 'linear-gradient(90deg, #ffd166, #2DC653)';
1565→    else if (pct >= 25) bar.style.background = 'linear-gradient(90deg, #ff9f1c, #ffd166)';
1566→    else bar.style.background = 'linear-gradient(90deg, #ef476f, #ff9f1c)';
1567→
1568→    const pctEl = document.getElementById('gaugePct');
1569→    pctEl.textContent = pct + '%';
1570→    pctEl.style.color = pct > 100 ? '#a855f7' : pct >= 50 ? '#2DC653' : pct >= 25 ? '#ff9f1c' : '#ef476f';
1571→
1572→    // 100% marker position: if pct > 100, marker moves left proportionally
1573→    const marker = document.getElementById('gaugeBar100');
1574→    if (pct > 100) marker.style.left = (100 / pct * 100) + '%';
1575→    else marker.style.left = '100%';
1576→
1577→    document.getElementById('gaugeUsers').textContent = sessionsActive + ' active / ' + stats.totalUsers + ' users';
1578→    document.getElementById('gaugeAvg').textContent = fmtMultiplier(stats.avgWeeklyPct || 0);
1579→
1580→    // Max possible gauge
1581→    let remainingPotentialUSD = 0;
1582→    data.users.forEach(u => {
